const rows = Array.from(document.querySelectorAll('.codebook-table .ant-table-tbody > tr.ant-table-row'));
const data = rows.map(tr => {
  const codeType = tr.querySelector('td:nth-child(1) span')?.innerText.trim() || '';
  const name = tr.querySelector('td:nth-child(2)')?.innerText.trim() || '';
  const desc = tr.querySelector('td:nth-child(3)')?.innerText.trim() || '';
  const status = tr.querySelector('td:nth-child(4) .pill')?.innerText.trim() || '';
  return { codeType, name, desc, status };
}).filter(r => r.codeType);
automaSetVariable('scraped_codebook_categories', data);
automaNextBlock({ categories: data });
